INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Visual content previews$q$, $q$Posts render as accurate, platform-specific mockups for Instagram, Facebook, LinkedIn, TikTok, X, Pinterest, YouTube, and Google Business Profile.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Approval workflows$q$, $q$Configurable sign-off stages let teams require approval from specific people before content moves to scheduled or published status.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Inline comments and mentions$q$, $q$Teammates and clients can comment, react, and tag collaborators directly on individual posts, keeping feedback in context.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Client workspaces$q$, $q$Separate workspaces isolate each client's content, team members, and permissions, making the platform easier to manage for agencies.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$White-label branding$q$, $q$Agencies can present a branded review experience to clients rather than exposing Planable's own branding.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Custom post statuses$q$, $q$Posts can be tagged with statuses such as draft, needs review, approved, or scheduled to track progress at a glance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Direct scheduling and publishing$q$, $q$Approved content can be scheduled or published straight to connected social accounts without exporting to another tool.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Bulk actions and duplication$q$, $q$Teams can duplicate posts, apply bulk edits, and reuse recurring content to speed up repetitive publishing tasks.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Role-based permissions$q$, $q$Admins can control who is allowed to edit, comment, approve, or publish, keeping oversight consistent across teams and clients.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Accurate, platform-specific previews make it easy to catch formatting issues before publishing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Structured approval workflows reduce back-and-forth email chains with clients and stakeholders$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Clean, calendar-based interface that is easy for non-technical clients to navigate$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Generous free plan makes it accessible for small teams or those testing the platform$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Client workspaces and white-label options suit agencies managing multiple accounts$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Costs can rise as more team members or client workspaces are added$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Analytics and reporting are more limited than dedicated social analytics tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$No built-in social listening or competitive monitoring features$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Some platform-specific publishing features can lag behind native scheduling tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Approval workflow setup requires some initial configuration to match a team's process$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$What is Planable used for?$q$, $q$Planable is used to plan, visually preview, collaborate on, approve, and schedule social media content across networks like Instagram, Facebook, LinkedIn, TikTok, X, and more, all in one shared workspace.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Does Planable have a free plan?$q$, $q$Yes, Planable offers a free plan with limited posts and workspace features, which is suitable for individuals or very small teams getting started with the platform.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Is Planable good for agencies managing multiple clients?$q$, $q$Yes, Planable's separate workspaces, white-label branding, and shareable client approval links are specifically designed to help agencies manage several client accounts from one place.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Can clients approve posts without creating a Planable account?$q$, $q$Yes, Planable supports shareable approval links so clients can review and approve or request changes to content without needing to log in or create an account.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Does Planable include analytics and reporting?$q$, $q$Planable includes basic reporting features, but it is primarily built around content collaboration and approvals rather than deep analytics, so teams needing advanced reporting may want to pair it with a dedicated analytics tool.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Managing multiple client accounts as an agency$q$, $q$Agencies use separate Planable workspaces to organize each client's content calendar, team members, and approval process while presenting a white-labeled review experience.$q$, $q$Social media agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Getting stakeholder sign-off before publishing$q$, $q$In-house marketing teams route posts through structured approval stages so brand, legal, or leadership can review content before it goes live.$q$, $q$In-house marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Collaborating with non-technical clients$q$, $q$Freelancers and consultants share visual previews and simple approval links so clients can give feedback without learning a complex tool.$q$, $q$Freelance social media managers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Coordinating content across a distributed team$q$, $q$Remote teams use inline comments, mentions, and shared calendars to keep everyone aligned on upcoming posts without relying on separate messaging tools.$q$, $q$Remote marketing and content teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["Limited number of posts","One workspace","Visual post previews","Basic commenting and collaboration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Basic$q$, $q$Starts around $13/user/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["More posts per workspace","Multiple workspaces","Approval workflows","Direct scheduling and publishing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Standard$q$, $q$Mid-tier pricing above Basic (billed annually)$q$, $q$Monthly or annual$q$, $q$["Expanded workspace and user limits","Custom post statuses","White-label client approval links","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$Advanced / Enterprise$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["Highest workspace and user limits","Advanced permissions and controls","Dedicated account support","Custom onboarding for large agencies or teams"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Planable is a social media collaboration and approval platform built to help marketing teams, agencies, and freelancers plan content together without the usual chaos of email threads, spreadsheets, and scattered feedback. Founded in 2017 and headquartered in Bucharest, Romania, the company built its reputation on one core idea: content should be reviewed the way it will actually appear on each social network, not as a plain text draft buried in a document.$q$, $q$At its center is a visual grid or calendar where posts show up as accurate previews for Instagram, Facebook, LinkedIn, TikTok, X, Pinterest, YouTube, and Google Business Profile. Teammates and clients can leave inline comments, tag collaborators, and react directly on the post mockup, which keeps feedback tied to context instead of scattered across separate tools.$q$, $q$Planable layers structured approval workflows on top of that visual foundation, letting teams define who needs to sign off before a post goes live and giving clients a simple, low-friction way to approve or request changes. It has become a common choice for agencies juggling many client accounts and in-house teams that need multiple stakeholders to review content before publishing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$who-planable-is-for$q$, $q$Who Planable Is For$q$, 2, ARRAY[$q$Social media agencies are a natural fit, since Planable's workspace structure lets each client's content, brand voice, and approval chain stay cleanly separated while still being managed from one shared account. White-label options and client-friendly approval links make it easier to present a polished, professional review process without asking clients to learn a complicated tool.$q$, $q$In-house marketing teams that need sign-off from legal, brand, or leadership before anything goes live also benefit, since Planable's status labels and approval stages replace the back-and-forth of email chains with a single visible thread of comments and decisions attached to each post.$q$, $q$Freelance social media managers and small marketing teams who work closely with non-technical clients tend to like Planable as well, because the platform is genuinely built around collaboration rather than around advanced scheduling or analytics, making it approachable for people who are not deep into marketing software day to day.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Solo creators or single-person brands with no one else to collaborate with may find Planable's core value proposition, approval workflows and shared review, largely unnecessary, and a lighter, cheaper scheduling tool could cover their needs just as well.$q$, $q$Teams that lean heavily on deep analytics, social listening, or competitive benchmarking should be cautious, since Planable's reporting is comparatively basic and is not designed to replace dedicated analytics or listening platforms.$q$, $q$Organizations looking for a single all-in-one suite that combines scheduling, advanced analytics, paid social management, and listening in one subscription may be better served by larger platforms like Sprout Social or Hootsuite, since Planable intentionally stays focused on content collaboration and approvals rather than trying to cover every marketing function.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Planable's visual content calendar and feed-preview views render posts as they will look on each target network, covering major platforms including Instagram, Facebook, LinkedIn, TikTok, X, Pinterest, YouTube, and Google Business Profile, so reviewers can catch layout or formatting issues before anything is published.$q$, $q$Collaboration tools sit at the heart of the platform: inline comments, @mentions, emoji reactions, and version history keep feedback attached directly to the specific post it concerns. Structured approval workflows let admins require sign-off from specific people before content moves to a scheduled or published state, with clear status labels showing where each post stands.$q$, $q$For agencies, separate workspaces keep client content and permissions isolated, while white-label branding and shareable, no-login approval links make client review simple. Additional features include custom post statuses, bulk actions, duplicate-and-reuse for recurring content, direct scheduling and publishing, and role-based permissions for managing who can edit, comment, or approve.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', $q$the-planable-experience$q$, $q$The Planable Experience$q$, 2, ARRAY[$q$New users typically find Planable's interface clean and quick to learn, since the grid and calendar layouts mirror familiar social feeds rather than presenting a dense dashboard of settings. Connecting social accounts and inviting collaborators or clients is a straightforward setup process that does not require much onboarding.$q$, $q$Day to day, the workflow tends to follow a consistent rhythm: drafts get created and previewed as native-looking posts, teammates and clients leave comments or reactions, statuses move from draft to pending approval to approved, and finally posts are scheduled or published directly from the same view, cutting out the need to jump between separate tools.$q$, $q$Overall, Planable's experience is strongest for teams whose main pain point is coordinating feedback and sign-off across multiple people. Users who need heavier analytics or broader marketing automation may find the experience narrower than expected, but for collaboration-first workflows the platform generally feels focused, visual, and low-friction.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
