INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d33a449d-fed5-4373-8185-a70d16979e8b', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Database Branching$q$, $q$Create isolated, git-like branches of a database schema to test changes before merging them into production.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Non-Blocking Schema Changes$q$, $q$Deploy requests apply schema edits through Vitess's online schema change tooling, avoiding long table locks during migrations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Horizontal Sharding$q$, $q$Vitess-based sharding lets a database scale out across many nodes as data volume and traffic grow.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Automatic Backups & Point-in-Time Recovery$q$, $q$Scheduled backups and recovery points help teams restore data after accidental changes or failures.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Query Insights$q$, $q$A built-in dashboard surfaces slow queries and indexing recommendations to help teams tune performance.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Connection Management$q$, $q$Built-in connection handling helps serverless and edge applications avoid overwhelming the database with short-lived connections.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Foreign Key Support$q$, $q$Foreign key constraints are supported within a single keyspace for teams that rely on relational integrity.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Multi-Region, Multi-Cloud Deployment$q$, $q$Clusters can be deployed across AWS and GCP regions, with dedicated networking options for teams with stricter requirements.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Read Replicas$q$, $q$Additional read replicas let teams scale read-heavy workloads separately from write traffic.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Postgres-Compatible Clusters$q$, $q$Alongside its original MySQL/Vitess offering, PlanetScale also provides Postgres-compatible database clusters.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Git-like branching and deploy requests make schema changes safer and reviewable$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Non-blocking schema migrations reduce the risk of production downtime$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Vitess-based horizontal sharding is proven at very large scale$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Built-in query insights help teams find and fix performance bottlenecks$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Managed backups, failover, and connection handling reduce day-to-day operational work$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$No free tier since 2024, so any use requires a paid, provisioned cluster$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Costs can grow significantly as cluster size, storage, and traffic increase$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Primarily oriented around relational MySQL/Postgres semantics, not other data models$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$The branching and deploy request workflow has a learning curve for teams new to it$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Reliance on a managed platform means less direct control than self-hosting Vitess$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Does PlanetScale have a free plan?$q$, $q$No. PlanetScale removed its free tier in 2024, and all databases now run on paid, usage-based cluster plans.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$What is database branching?$q$, $q$It's a workflow where developers create an isolated copy of a database schema, make changes there, and merge those changes into production through a reviewable deploy request rather than a direct migration.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Is PlanetScale built on open-source technology?$q$, $q$Yes. It's built on Vitess, an open-source MySQL clustering system originally created at YouTube, though the PlanetScale platform itself is a proprietary managed service.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Does PlanetScale support foreign keys?$q$, $q$Yes, foreign key constraints are supported as long as the related tables live within the same keyspace.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Can I use PlanetScale with Postgres instead of MySQL?$q$, $q$Yes. In addition to its original Vitess-based MySQL offering, PlanetScale now also offers Postgres-compatible database clusters.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Scaling MySQL Without Managing Vitess$q$, $q$Teams running MySQL at growing scale get horizontal sharding and replication managed for them instead of operating Vitess in-house.$q$, $q$Engineering teams running high-traffic production applications$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Safer Schema Migrations$q$, $q$Branching and non-blocking deploy requests let teams review and ship schema changes with far less risk of production downtime.$q$, $q$Product engineering teams shipping frequent schema changes$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Multi-Tenant SaaS with Variable Traffic$q$, $q$Usage-based, cluster-size pricing lets SaaS teams size their database to fluctuating tenant load without switching platforms.$q$, $q$SaaS companies with unpredictable or seasonal traffic$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Startup to Enterprise Growth Path$q$, $q$Teams can start on a smaller cluster and scale the same underlying platform up as data volume and traffic increase over time.$q$, $q$Startups anticipating rapid user and data growth$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Vitess (Non-Metal)$q$, $q$From $39/month$q$, $q$Monthly$q$, $q$["Vitess-based MySQL-compatible clusters","Horizontal sharding","Database branching and deploy requests","Automatic backups"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Vitess Metal$q$, $q$From $609/month$q$, $q$Monthly$q$, $q$["Dedicated hardware for higher, more consistent performance","Horizontal sharding at larger scale","Automatic backups and point-in-time recovery","Query insights"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Custom$q$, $q$["Dedicated VPC peering and networking options","Custom support and SLAs","Compliance and security add-ons","Multi-cloud and multi-region deployment"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PlanetScale is a managed, serverless database platform built on top of Vitess, the clustering system originally created at YouTube to scale MySQL horizontally. The company packages that battle-tested sharding technology into a product that lets engineering teams run production MySQL-compatible databases without operating Vitess themselves, handling replication, failover, backups, and scaling behind a managed control plane.$q$, $q$What sets PlanetScale apart from a typical hosted database is its workflow around schema changes. Instead of running migrations directly against a live database, teams create a database branch, make schema edits in isolation, and submit a deploy request that PlanetScale applies without locking tables. This git-inspired approach is meant to make schema evolution feel closer to how teams already review and ship application code.$q$, $q$The platform has evolved past its original MySQL-only focus, adding a Postgres-compatible offering alongside its Vitess-based clusters. It has also moved away from a free tier: as of 2024, PlanetScale is paid-only, with pricing based on the cluster size a team provisions plus usage for storage, backups, and data transfer. That shift positions it more clearly as infrastructure for production workloads rather than side projects or evaluation-only use.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$who-planetscale-is-for$q$, $q$Who PlanetScale Is For$q$, 2, ARRAY[$q$PlanetScale is aimed at engineering teams running production applications on MySQL who anticipate needing horizontal scale but don't want to build and operate their own Vitess cluster. Teams that have outgrown a single-instance database, or that expect to, get access to sharding and replication expertise without hiring for it internally.$q$, $q$It also suits teams that want a safer way to change database schemas. Because every schema edit goes through a branch and a reviewable deploy request rather than a manual ALTER TABLE against production, PlanetScale appeals to organizations that have been burned by risky migrations or that want schema changes to go through the same review discipline as application code.$q$, $q$Startups anticipating rapid growth, and SaaS companies with multi-tenant, traffic-variable workloads, are a natural fit as well. Usage-based, cluster-size pricing means a small team can start on a modest configuration and scale the same platform up as load grows, without a migration to different database infrastructure later on.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Hobbyists, students, and very early-stage side projects that previously relied on PlanetScale's free tier should look elsewhere, since that tier no longer exists. Anyone wanting to run a database at effectively no cost while experimenting will find simpler, cheaper managed database options better suited to that stage.$q$, $q$Teams whose data model doesn't fit relational databases at all, heavy document, graph, or wide-column workloads, won't gain much from PlanetScale's MySQL and Postgres compatibility layers, since the platform's core value is scaling relational schemas, not replacing them with a different data model.$q$, $q$Organizations with strict requirements to self-host or keep all infrastructure on-premises should also be cautious, since PlanetScale is a managed cloud service rather than software you install and run yourself. Budget-constrained teams should also weigh that cluster and usage costs grow with data size and traffic, which can surprise teams that don't monitor consumption closely.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The centerpiece of PlanetScale's product is database branching combined with non-blocking schema changes. Developers create a branch of the database schema, test changes against it, then open a deploy request that PlanetScale's underlying Vitess engine applies to production without holding long-running table locks, reducing the risk of downtime during migrations.$q$, $q$Underneath that workflow sits Vitess-powered horizontal sharding, letting a database grow across many underlying nodes as data volume increases, along with automatic backups, point-in-time recovery, and read replicas for scaling read-heavy workloads. Connection management features help serverless and edge applications avoid exhausting database connections under bursty traffic.$q$, $q$PlanetScale also provides query insights that surface slow queries and indexing opportunities directly in its dashboard, support for foreign key constraints within a keyspace, and deployment across multiple cloud regions with options like dedicated VPC peering for teams with stricter networking or compliance needs.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', $q$the-planetscale-experience$q$, $q$The PlanetScale Experience$q$, 2, ARRAY[$q$Day to day, working with PlanetScale feels closer to a software engineering workflow than a traditional database admin console. Creating a branch, editing a schema, and opening a deploy request mirrors the branch-and-pull-request cycle developers already use for code, which is deliberate on PlanetScale's part and tends to shorten the learning curve for engineering teams.$q$, $q$The dashboard surfaces query insights, connection metrics, and deploy request status in one place, giving teams visibility into database health without needing separate monitoring tooling for basic diagnostics. The CLI and integrations with common frameworks and ORMs are built to keep the branching workflow close to a team's existing development tools.$q$, $q$Overall, the experience trades some operational simplicity and low starting cost for the confidence of Vitess's scaling track record and a more disciplined migration process. Teams that value safety and horizontal scale headroom tend to find that trade-off worthwhile, while teams just looking for the cheapest possible managed MySQL instance may find the value proposition less compelling now that pricing starts higher than it once did.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('424ed87f-e0ac-4a99-869c-2cecd795e4b1', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
