INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Is PlanGrid still sold as a standalone product?$q$, $q$PlanGrid's core capabilities have largely been integrated into Autodesk Construction Cloud, primarily Autodesk Build and Autodesk Docs, so most new customers are onboarded through those products rather than a separate PlanGrid purchase.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$How much does PlanGrid cost?$q$, $q$Pricing is not publicly published; Autodesk sells it through a quote-based process based on company size, number of projects, and required features, so prospective buyers need to contact sales directly.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Does PlanGrid work offline?$q$, $q$Yes, the mobile app is designed for job sites with limited connectivity, allowing drawing markups and field data entry offline that syncs automatically once a connection is restored.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$What platforms is PlanGrid available on?$q$, $q$It is available as a web application for office use and as native mobile apps for iOS and Android, which field teams use on tablets and phones at job sites.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Who owns PlanGrid?$q$, $q$PlanGrid was acquired by Autodesk in 2018 and is now part of the Autodesk Construction Cloud portfolio alongside products like Autodesk Build and BIM 360.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Field drawing markup and version control$q$, $q$Superintendents and foremen mark up the latest drawing revisions directly on-site and share annotations instantly with the rest of the team.$q$, $q$General contractors and site superintendents$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$RFI and submittal management$q$, $q$Design teams and contractors track requests for information and submittal approvals against a documented, drawing-linked history.$q$, $q$Architecture and engineering firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Punch list and closeout tracking$q$, $q$Teams log, assign, and verify punch list items tied to specific locations on a drawing as a project nears completion.$q$, $q$Subcontractors and project managers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Portfolio-level progress reporting$q$, $q$Owners and program managers compare field reports, photos, and open issue counts across multiple job sites in one place.$q$, $q$Owners and multi-project program managers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Standard$q$, $q$Contact for pricing$q$, $q$Annual$q$, $q$["Blueprint markup and version control","Field reports and photo documentation","Mobile offline access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Business$q$, $q$Contact for pricing$q$, $q$Annual$q$, $q$["RFIs and submittals","Punch lists","Advanced reporting and dashboards"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$Enterprise / Autodesk Construction Cloud$q$, $q$Contact for pricing$q$, $q$Annual$q$, $q$["Integration with Autodesk Build, Docs, and BIM 360","Portfolio-level project management","Custom onboarding and support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PlanGrid began in 2011 as a mobile app for viewing and marking up construction blueprints on a tablet, replacing the stacks of paper drawings that superintendents and foremen once carried to job sites. Autodesk acquired the company in 2018 and has since folded its capabilities into Autodesk Construction Cloud, where PlanGrid functionality now largely lives inside Autodesk Build and Autodesk Docs.$q$, $q$At its core, PlanGrid gives project teams a single, synced source of truth for drawings, specifications, and field data. Superintendents mark up sheets on-site, RFIs and submittals route automatically to the right reviewers, and punch lists and field reports get tied directly to the sheet location they reference, cutting down on the version confusion that plagues paper-based job sites.$q$, $q$Because it now sits inside the broader Autodesk Construction Cloud ecosystem, PlanGrid-style workflows connect to BIM models, cost management, and scheduling tools used earlier and later in a project's lifecycle. That positioning makes it most relevant to teams already invested in, or considering, the Autodesk stack for end-to-end construction management rather than a narrow, standalone point solution.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$who-plangrid-is-for$q$, $q$Who PlanGrid Is For$q$, 2, ARRAY[$q$General contractors and subcontractors running active job sites are the core audience. Field crews benefit most from real-time drawing markup, offline mobile access, and the ability to see the latest sheet revision instantly instead of waiting for a printed set to circulate, which matters on fast-moving commercial, industrial, or infrastructure projects.$q$, $q$Architecture and engineering firms that need a structured way to receive and respond to RFIs and submittals from contractors also find value here, since the workflow keeps a documented paper trail tied to specific drawings and dates, which helps with accountability and later dispute resolution.$q$, $q$Owners and project managers overseeing multiple concurrent projects benefit from standardized punch lists, field reports, and photo documentation across job sites, giving them a consistent way to compare progress and quality across a portfolio rather than relying on each site team's own ad hoc reporting habits.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very small contractors, solo tradespeople, or teams running one or two simple residential jobs at a time may find the platform more structure and cost than their workflow needs, especially if a shared folder of PDFs and a group chat currently gets the job done well enough.$q$, $q$Buyers who want transparent, self-serve pricing they can compare instantly will likely be frustrated, since PlanGrid and the rest of Autodesk Construction Cloud are sold through a quote-based sales process rather than published per-seat rates, which slows down evaluation for smaller companies.$q$, $q$Teams with no intention of adopting the wider Autodesk ecosystem, or that already run a lighter competing field-management tool their crews like, may not see enough incremental benefit to justify a migration, particularly if their document volume and RFI workload are modest.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Blueprint and document management sits at the center of the product: drawings are uploaded, auto-versioned, and hyperlinked so that details, sections, and callouts on one sheet link directly to the referenced sheet, and every field user always opens the current revision instead of an outdated print.$q$, $q$Field workflow tools cover RFIs, submittals, punch lists, and daily field reports, each of which can be tied to a location on a drawing or a photo taken on-site. Markups, annotations, and photo pins sync across devices so office and field staff are always looking at the same information.$q$, $q$Collaboration and reporting round out the platform, with role-based permissions, activity history, and dashboards that let project managers track open issues, overdue RFIs, and punch-list completion across a project or a portfolio, plus integration paths into Autodesk Build, Docs, and BIM 360 for teams using the larger Autodesk Construction Cloud suite.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9b3f0303-3e4e-44b8-b85b-8e246173d906', $q$the-plangrid-experience$q$, $q$The PlanGrid Experience$q$, 2, ARRAY[$q$Day to day, most field users interact with PlanGrid through its mobile app on a tablet or phone, marking up sheets, snapping photos, and logging issues directly from the job site, with offline access that syncs automatically once a connection is available again.$q$, $q$Office-based project staff work more from the web interface, setting up projects, managing document sets, assigning RFIs, and pulling reports for stakeholders or owners. The split between a field-optimized mobile app and a more administrative web dashboard is a deliberate design choice reflecting how construction teams actually operate.$q$, $q$Since the acquisition, the standalone PlanGrid brand has been gradually absorbed into Autodesk Construction Cloud, so new customers are typically onboarded into Autodesk Build rather than a separate PlanGrid product. Existing PlanGrid users generally describe the underlying field workflows as intuitive, though the ongoing consolidation has meant some adjustment as menus, plans, and terminology shift toward the Autodesk naming.$q$]::text[], 4);
