INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Overkill for small teams or organizations that only need basic task tracking$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Learning curve for administrators and end users is steeper than with lightweight project tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$What is Planview used for?$q$, $q$Planview is used by enterprises to manage strategic portfolios, projects, products, and resources in one connected system, giving leadership visibility into how work aligns with business strategy.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$How much does Planview cost?$q$, $q$Planview does not publish standard pricing. Costs depend on which products, modules, and number of users an organization needs, and are quoted through a sales conversation.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Does Planview support agile teams?$q$, $q$Yes. Planview includes Lean-Agile delivery boards and portfolio tools designed to support Kanban and scaled agile frameworks alongside traditional project management.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Is Planview suitable for small businesses?$q$, $q$Generally no. Planview is built for large and midsize enterprises with complex portfolios; small teams needing simple task tracking are usually better served by lighter tools.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Does Planview offer AI features?$q$, $q$Yes, Planview has introduced AI-assisted capabilities under the Planview Copilot branding that help surface portfolio insights and reduce manual reporting effort.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$IT Portfolio Governance$q$, $q$PMOs and IT leaders use Planview to prioritize and track technology investments against strategic goals.$q$, $q$PMOs and IT leadership$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Scaled Agile Delivery$q$, $q$Organizations running multiple agile teams use Planview's Lean-Agile boards to coordinate delivery within a broader portfolio.$q$, $q$Agile delivery teams and coaches$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Resource & Capacity Planning$q$, $q$Resource managers use Planview to see allocation across projects and rebalance workloads before bottlenecks occur.$q$, $q$Resource managers and operations leads$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Professional Services Delivery$q$, $q$Services organizations use Planview PSA capabilities to connect project delivery with time tracking and billing.$q$, $q$Professional services firms$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Team$q$, $q$Contact for pricing$q$, $q$Annual$q$, $q$["Lean-Agile delivery boards","Basic reporting","Team-level collaboration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$Annual$q$, $q$["Portfolio and project management","Resource and capacity management","Advanced reporting and dashboards","Integrations with third-party tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$Enterprise Plus$q$, $q$Contact for pricing$q$, $q$Annual$q$, $q$["Strategic portfolio management","Product portfolio management","Professional services automation","Planview Copilot AI capabilities","Dedicated implementation support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Planview is an enterprise portfolio and work management platform that helps large organizations connect strategy to execution across projects, products, teams, and resources. Rather than being a single application, it is a suite of connected products covering strategic portfolio management, project and Lean-Agile delivery, product portfolio management, resource and capacity planning, and professional services automation. It is built for organizations running many concurrent initiatives across departments rather than a single small team managing a handful of tasks.$q$, $q$The company traces back to 1989 and has grown substantially through a long series of acquisitions, absorbing tools such as Clarizen, LeanKit, Innotas, Troux, Changepoint, and Projectplace into a broader Planview brand. That history means the platform today spans multiple underlying products and interfaces rather than one unified codebase, each historically strong in a particular discipline such as IT portfolio governance, enterprise architecture, or Kanban-style delivery boards.$q$, $q$For enterprises wrestling with fragmented spreadsheets, disconnected project tools, and limited visibility into capacity, Planview aims to be the layer that ties strategic goals, funded initiatives, delivery teams, and reporting together. It is typically evaluated by PMOs, transformation offices, and IT leadership rather than purchased informally by an individual team, and it is usually implemented with the help of Planview's own services or certified partners.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$who-planview-is-for$q$, $q$Who Planview Is For$q$, 2, ARRAY[$q$Planview is best suited to large and midsize enterprises with mature or maturing project and portfolio management practices, particularly those managing IT investment portfolios, digital transformation programs, or scaled agile delivery across many teams. PMOs, enterprise architects, resource managers, and executives who need roll-up visibility across dozens or hundreds of initiatives are the core audience, since the platform's value grows with the number of interconnected projects and teams it can represent.$q$, $q$Organizations already using a scaled agile framework, or planning to introduce one, often turn to Planview because several of its products were built specifically to support Lean-Agile portfolio management alongside traditional waterfall project tracking. Professional services organizations that need to tie resource allocation, utilization, and billing together also fit well, since Planview's PSA capabilities were built for exactly that combination of delivery and financial tracking.$q$, $q$IT and business leaders accountable for demonstrating how spend maps to strategic outcomes are another strong fit, because the platform's reporting and roadmap tools are designed around portfolio-level governance rather than day-to-day task management alone. Companies undergoing a formal PPM or SPM rollout, with dedicated administrators and change management support, tend to get the most value from the investment.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Small businesses, startups, and lean teams that just need a simple way to track tasks or a lightweight project board will likely find Planview far more than they need, both in configuration overhead and in cost. Teams looking for a quick self-serve signup with transparent, published pricing should also look elsewhere, since Planview is sold through a sales-led enterprise process rather than an instant online checkout.$q$, $q$Organizations without a dedicated PMO, portfolio administrator, or internal champion may struggle to get value from the platform, since realizing its benefits usually requires deliberate configuration of portfolios, workflows, and reporting rather than out-of-the-box simplicity. Teams that want a single, tightly unified interface may also find the experience uneven, since different Planview products retain some of the look and feel of the tools they originated from.$q$, $q$Finally, organizations that primarily need simple task or bug tracking, a basic shared calendar, or a lightweight collaboration tool are likely to be better served by smaller, purpose-built products. Planview's strength is portfolio-level governance and cross-team resource visibility, and teams without that need will find much of its depth goes unused.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Planview's suite covers strategic portfolio management, which links corporate strategy to funded initiatives and helps leaders see how investments map to outcomes. Its project portfolio management tools support intake, prioritization, and tracking of projects, while dedicated Lean-Agile delivery boards support Kanban and scaled agile teams working alongside traditional project structures.$q$, $q$Resource and capacity management is a core strength, letting organizations see where people are allocated across projects and identify over- or under-utilization before it becomes a bottleneck. Product portfolio management tools help product organizations plan roadmaps and align investment with product strategy, while professional services automation ties time tracking, utilization, and billing together for services-driven businesses.$q$, $q$Cross-cutting these modules are reporting and dashboarding capabilities intended to give executives roll-up visibility across many initiatives at once, along with integrations to tools like Jira, Azure DevOps, Microsoft Teams, Slack, and Power BI so Planview can sit above delivery teams' existing tools rather than replace them. Planview has also introduced AI-assisted capabilities, branded as Planview Copilot, that surface insights and summarize portfolio data to reduce manual reporting work.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', $q$the-planview-experience$q$, $q$The Planview Experience$q$, 2, ARRAY[$q$Using Planview generally feels like adopting an enterprise system rather than signing up for a lightweight app: implementation typically involves configuration workshops, an assigned customer success or professional services contact, and a rollout that touches how portfolios, workflows, and permissions are structured for the whole organization. Administrators get considerable control over how the system models an organization's work, but that flexibility comes with a learning curve.$q$, $q$Because the product line grew through acquisition, day-to-day use can feel different depending on which Planview module a person works in, from portfolio dashboards to Kanban boards to services-oriented time entry screens. Larger organizations often deploy multiple Planview products together, which Planview positions as an integrated platform, though users moving between modules may still notice differences in interface conventions and terminology.$q$, $q$Ongoing use tends to center on recurring portfolio reviews, capacity planning cycles, and status reporting rather than moment-to-moment task chatter, reflecting its design for governance and planning cadences. Organizations that invest in proper configuration, training, and internal champions generally report that the platform becomes central to how they run their PMO or delivery organization, while those expecting a plug-and-play experience may find the ramp-up longer than with smaller point solutions.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c9f13c9-cf6c-446e-bb2f-8847796544ec', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
