INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Coaching & Webinars$q$, $q$Sell one-on-one calls, group coaching, and live webinars with built-in scheduling and payment collection.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Email Marketing$q$, $q$Send broadcasts and simple automated sequences to your audience without needing a separate email service provider.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Website & Storefront Builder$q$, $q$Build a public-facing storefront and sales pages using customizable, template-based design tools.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Affiliate Marketing$q$, $q$Let customers or partners earn commissions promoting your products through a built-in affiliate program.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Payments & Checkout$q$, $q$Accept one-time payments, subscriptions, and payment plans with integrated Stripe and PayPal checkout.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Zapier & App Integrations$q$, $q$Connect Podia to other tools in your stack through native integrations and Zapier automations.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Easy to set up and use, even for creators with no technical background$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Combines courses, downloads, memberships, coaching, and email marketing in one place$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Free plan lets new creators start selling before paying anything$q$, 2);
