INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Website and email design customization is more limited than dedicated tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Free plan charges a transaction fee on sales$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$No native mobile app for creators or students$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Advanced marketing automation is thinner than dedicated email platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Does Podia have a free plan?$q$, $q$Yes, Podia offers a free plan that lets creators sell digital downloads and limited products, though it includes a per-sale transaction fee that paid plans remove or reduce.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$What can you sell on Podia?$q$, $q$Podia supports selling online courses, digital downloads, memberships, coaching sessions, and webinars, all managed from a single dashboard.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Does Podia charge transaction fees?$q$, $q$The free plan charges a transaction fee on sales, while Podia's paid plans remove or significantly reduce that fee depending on the tier.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Can I migrate my existing courses and students to Podia?$q$, $q$Podia provides migration guidance and support for importing existing courses, student lists, and email subscribers from other platforms.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Is there a Podia mobile app?$q$, $q$Podia does not offer a dedicated native mobile app; the platform is designed to be used through a web browser on both desktop and mobile devices.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Launching an Online Course$q$, $q$Package expertise into a self-paced or cohort-based course with video lessons, downloadable materials, and drip scheduling.$q$, $q$Educators and subject-matter experts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Selling Digital Products$q$, $q$Distribute ebooks, templates, presets, or other files with instant delivery and simple checkout.$q$, $q$Designers, writers, and digital product creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Running a Paid Membership Community$q$, $q$Build a recurring-revenue community with gated posts and discussions for ongoing member engagement.$q$, $q$Community builders and niche experts$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Offering Coaching or Consulting$q$, $q$Sell scheduled one-on-one or group coaching sessions with integrated booking and payment collection.$q$, $q$Coaches and consultants$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Sell digital downloads","Limited course and membership features","Per-sale transaction fee applies"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Mover$q$, $q$From around $33/month billed annually$q$, $q$Monthly or annual$q$, $q$["Unlimited courses and digital downloads","Email marketing","No transaction fees"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$Shaker$q$, $q$From around $75/month billed annually$q$, $q$Monthly or annual$q$, $q$["Everything in Mover","Memberships and coaching products","Affiliate marketing","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Podia has grown from a small side project into a well-established, all-in-one platform for creators who want to sell online courses, digital downloads, memberships, and coaching without stitching together a dozen separate tools. Founded in 2014, the company set out to give solo creators and small teams a single home for their storefront, product delivery, email marketing, and payments, rather than forcing them to pay for and manage a course platform, an email service, a payment processor, and a website builder separately. That "one login, one dashboard" philosophy remains Podia's core pitch today, and it has kept the product relevant even as the creator economy has grown far more crowded.$q$, $q$Unlike heavier learning management systems built for corporate training departments, Podia is deliberately simple. Creators upload content, set a price, and publish a page within minutes, with Podia handling hosting, checkout, taxes on digital sales, and student or customer access automatically. The platform supports one-time purchases, subscriptions, payment plans, and free content, giving creators flexibility in how they package what they sell, whether that's a single ebook or a recurring membership.$q$, $q$Podia's free plan lets new creators test the waters before committing to a paid tier, while its paid plans unlock features like memberships, coaching products, affiliate marketing, and reduced or eliminated transaction fees. This tiered structure has made Podia a popular starting point for people monetizing an audience for the first time, as well as a longer-term home for established creators who value simplicity over deep customization.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$who-podia-is-for$q$, $q$Who Podia Is For$q$, 2, ARRAY[$q$Podia is built for independent creators, coaches, consultants, and small businesses who want to monetize knowledge or a following without hiring developers. Course creators teaching a skill, cohort-based educators, and subject-matter experts packaging a signature framework all fit naturally, since Podia's course builder handles video hosting, drip content, and student progress with minimal setup required from the creator.$q$, $q$It also suits creators selling digital downloads such as templates, ebooks, presets, or software, and community builders who want a paid membership space with posts, discussions, and gated content. Coaches and consultants who sell one-on-one calls or group programs benefit from Podia's built-in scheduling and webinar tools, avoiding the need to bolt on a separate booking system just to collect payment for their time.$q$, $q$Because Podia bundles email marketing and a basic storefront alongside its product tools, it's a strong fit for anyone who wants a single vendor relationship rather than juggling multiple subscriptions. Solopreneurs and small teams who prioritize speed to launch over granular control tend to get the most value from the platform, especially early on.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Podia is a weaker fit for large training organizations or universities that need formal LMS features such as quizzes, certifications, SCORM compliance, or detailed learner analytics, since Podia's course tools are intentionally streamlined rather than exhaustive. Enterprises with compliance or accreditation requirements should look at dedicated LMS software instead of trying to adapt Podia to that use case.$q$, $q$Creators who need highly customized storefront design, advanced marketing automation with complex branching logic, or a native mobile app for their audience may also find Podia limiting, since its website and email builders trade flexibility for simplicity. Teams that have already invested heavily in a specialized email platform or a separate community tool may find some overlap frustrating rather than helpful.$q$, $q$Finally, sellers with very high sales volumes who are sensitive to per-transaction fees on the free plan, or who need granular affiliate and tax reporting beyond what Podia natively provides, may eventually outgrow the platform and look toward more specialized, modular tooling as their business scales.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Podia offers an online course builder supporting video, downloadable resources, quizzes, and drip scheduling, so creators can structure self-paced or cohort-based learning experiences without technical setup. Digital downloads let creators sell files like ebooks, templates, and presets with instant delivery and license-friendly hosting for buyers.$q$, $q$Membership and community features allow creators to run paid, gated communities with posts and discussion threads, while coaching and webinar tools support scheduled calls, group sessions, and live events with built-in payment collection. An integrated email marketing tool lets creators send broadcasts and simple automated sequences to their audience without a separate email service provider to manage.$q$, $q$Rounding out the toolkit, Podia includes a website and storefront builder for a creator's public-facing page, an affiliate marketing feature so customers or partners can earn commissions promoting products, and native integrations with payment processors like Stripe and PayPal alongside Zapier for connecting to other apps in a creator's broader stack.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', $q$the-podia-experience$q$, $q$The Podia Experience$q$, 2, ARRAY[$q$Using Podia generally feels calm and uncluttered compared to more feature-dense platforms, since its dashboard organizes courses, downloads, memberships, and coaching products under one clear navigation structure. New users typically publish their first product within a single sitting, guided by onboarding checklists and templates rather than a steep learning curve or lengthy setup wizard.$q$, $q$Customer support is frequently cited as a strength, with responsive live chat available to help creators troubleshoot setup, payments, or migration from another platform. Podia also provides guidance for importing existing courses, students, and email lists, which lowers the friction of switching from a competitor to Podia.$q$, $q$The tradeoff for that simplicity is less granular control: design customization is more template-driven than a dedicated website builder, and deeper marketing automation or analytics require pairing Podia with additional tools. For creators who value a fast, low-maintenance setup over pixel-level customization, the overall experience remains one of Podia's most consistent selling points.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('11aeaa6f-ca3a-4980-80c9-07d68c56564a', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
