INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff342572-8c41-421f-88e9-ab4155b8dbbf', $q$AI Assistant$q$, $q$Generate test scripts, documentation, and debugging suggestions using an integrated AI helper.$q$, 8);
