INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff342572-8c41-421f-88e9-ab4155b8dbbf', $q$Strong automation support through scripting, the Collection Runner, and the Newman CLI for CI/CD$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff342572-8c41-421f-88e9-ab4155b8dbbf', $q$Effective team collaboration via shared workspaces, comments, and synced collections$q$, 3);
