INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff342572-8c41-421f-88e9-ab4155b8dbbf', $q$Cloud sync of collections may not suit teams with strict data residency requirements$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff342572-8c41-421f-88e9-ab4155b8dbbf', $q$Higher-tier paid plans are priced per user, which can add up for larger teams$q$, 2);
